
class ServiceStatus {final LoadBalancerStatus? loadBalancer; final List<ServiceCondition>? conditions; ServiceStatus({this.loadBalancer, this.conditions}); factory ServiceStatus.fromJson(Map<String, dynamic> json) {return ServiceStatus(loadBalancer: json['loadBalancer'] != null ? LoadBalancerStatus.fromJson(json['loadBalancer']) : null, conditions: json['conditions'] != null ? (json['conditions'] as List).map((e) => ServiceCondition.fromJson(e)).toList() : null);} Map<String, dynamic> toJson() {return {if (loadBalancer != null) 'loadBalancer' : loadBalancer!.toJson(), if (conditions != null) 'conditions' : conditions!.map((e) => e.toJson()).toList()};}}
